template<typename T, typename E>
class Expected {
private:
    union {
        T value_;
        E error_;
    };
    bool has_value_;

public:
    Expected(const T& val) : value_(val), has_value_(true) {}
    Expected(const E& err) : error_(err), has_value_(false) {}

    ~Expected() {
        if (has_value_) value_.~T();
        else error_.~E();
    }
};

template<typename F>
auto and_then(F&& f) -> decltype(f(std::declval<T>())) {
    using ReturnType = decltype(f(std::declval<T>()));
    if (has_value_) {
        return f(value_);
    }
    return ReturnType(error_);
}
